// pickerSpriteFor resolves the preview record for an entity, defaulting
// to (false, _) when the picker handler couldn't produce one (e.g. the
// entity has no SpriteAssetID, or the asset row was deleted).
func pickerSpriteFor(p PickerProps, id int64) (EntitySpritePreview, bool) {
	if p.EntitySprite == nil {
		return EntitySpritePreview{}, false
	}
	sp, ok := p.EntitySprite[id]
	if !ok || sp.URL == "" {
		return EntitySpritePreview{}, false
	}
	return sp, true
}

// pickerSpriteStyle is the picker-card analog of paletteThumbStyle in
// mapmaker.templ — same atlas-clip math, scaled up to 64px so the
// thumbnails read well inside the modal grid.
func pickerSpriteStyle(sp EntitySpritePreview) string {
	cols := int(sp.AtlasCols)
	if cols <= 0 {
		cols = 1
	}
	idx := int(sp.AtlasIndex)
	col := idx % cols
	row := idx / cols
	const thumb = 64
	totalW := thumb * cols
	return fmt.Sprintf(
		"display:block;width:%dpx;height:%dpx;background-image:url('%s');background-repeat:no-repeat;background-size:%dpx auto;background-position:-%dpx -%dpx;image-rendering:pixelated;",
		thumb, thumb, sp.URL, totalW, col*thumb, row*thumb,
	)
}

// pickerSearchURL builds the GET endpoint for HTMX-driven search.
// The kind drives the route; tag/target params ride along so the
// server-side handler can rebuild the filtered grid.
func pickerSearchURL(p PickerProps) string {
	if p.Kind == "asset" {
		return "/design/picker/assets"
	}
	return "/design/picker/entities"
}

